const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const activityLogSchema = new mongoose.Schema(
  {
    category: {
      type: String,
      enum: ['opportunity', 'funder', 'application', 'match', 'ai', 'user', 'system'],
      required: true,
    },
    action: { type: String, required: true },
    summary: { type: String, required: true },
    severity: { type: String, enum: ['info', 'warning', 'error'], default: 'info' },
    actorId: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
    meta: { type: mongoose.Schema.Types.Mixed },
  },
  { timestamps: true }
);

activityLogSchema.index({ createdAt: -1 });
activityLogSchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('ActivityLog', activityLogSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const agencySchema = new mongoose.Schema(
  {
    name: { type: String, required: true, trim: true },
    type: {
      type: String,
      required: true,
      enum: [
        'law_enforcement', 'fire_services', 'ems', 'emergency_management',
        '911_centers', 'hospitals', 'public_safety_comms', 'multi_agency',
      ],
    },
    location: { type: String },
    grantContactEmail: { type: String, lowercase: true },
    matchCount: { type: Number, default: 0 },
    status: { type: String, enum: ['active', 'inactive'], default: 'active' },
  },
  { timestamps: true }
);

agencySchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('Agency', agencySchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const alertSchema = new mongoose.Schema(
  {
    organization: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization' },
    opportunity: { type: mongoose.Schema.Types.ObjectId, ref: 'Opportunity' },
    user: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
    orgName: { type: String },
    grantName: { type: String },
    type: {
      type: String,
      enum: ['deadline', 'high_fit', 'deadline_updated', 'no_match', 'application_update'],
      required: true,
    },
    priority: { type: String, enum: ['high', 'medium', 'low'], default: 'medium' },
    message: { type: String, required: true },
    isRead: { type: Boolean, default: false },
    alertKey: { type: String },
  },
  { timestamps: true }
);

alertSchema.virtual('read').get(function () {
  return this.isRead;
});

alertSchema.virtual('userId').get(function () {
  return this.user;
});

alertSchema.set('toJSON', { virtuals: true });
alertSchema.set('toObject', { virtuals: true });

alertSchema.index({ alertKey: 1 }, { unique: true, sparse: true });
alertSchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('Alert', alertSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const applicationSchema = new mongoose.Schema(
  {
    organization: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization', required: true },
    opportunity: { type: mongoose.Schema.Types.ObjectId, ref: 'Opportunity' },
    status: {
      type: String,
      enum: [
        'draft',
        'submitted',
        'in_review',
        'approved',
        'awarded',
        'rejected',
        'not_started',
        'drafting',
        'ready_to_submit',
        'follow_up_needed',
        'denied',
      ],
      default: 'draft',
    },
    projectTitle: { type: String },
    projectSummary: { type: String },
    communityImpact: { type: String },
    amountRequested: { type: Number },
    timeline: { type: String },
    contactName: { type: String },
    contactEmail: { type: String, lowercase: true },
    submittedAt: { type: Date },

    // AI-generated structured sections
    problemStatement: { type: String },
    proposedSolution: { type: String },
    measurableOutcomes: { type: String },
    urgency: { type: String },
    budgetSummary: { type: String },

    // Funder-aligned version (AI rewrite)
    alignedVersion: {
      problemStatement: String,
      communityImpact: String,
      proposedSolution: String,
      measurableOutcomes: String,
      urgency: String,
      budgetSummary: String,
      generatedAt: Date,
    },

    // Submission tracker fields
    dateStarted: { type: Date, default: Date.now },
    dateSubmitted: { type: Date },
    followUpDate: { type: Date },
    notes: { type: String },

    statusHistory: [
      {
        status: { type: String },
        previousStatus: { type: String },
        changedAt: { type: Date, default: Date.now },
        changedBy: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
      },
    ],

    // Win database tagging
    isWinner: { type: Boolean, default: false },
    winTags: {
      fundingType: String,
      agencyType: String,
      projectType: String,
    },

    // Reference to the funder (new Funder model)
    funder: { type: mongoose.Schema.Types.ObjectId, ref: 'Funder' },

    // User who created/submitted this application (best-effort; may be null for legacy records)
    submittedBy: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  },
  { timestamps: true }
);

applicationSchema.plugin(mongoosePaginateV2);

applicationSchema.index({ organization: 1, status: 1 });
applicationSchema.index({ organization: 1, createdAt: -1 });
applicationSchema.index({ funder: 1 });

module.exports = mongoose.model('Application', applicationSchema);

const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const userSchema = new mongoose.Schema(
  {
    fullName: { type: String, trim: true },
    firstName: { type: String, trim: true },
    lastName: { type: String, trim: true },
    email: { type: String, required: true, unique: true, lowercase: true, trim: true },
    password: { type: String, required: true, minlength: 8, select: false },
    role: { type: String, enum: ['agency', 'admin'], default: 'agency' },
    isActive: { type: Boolean, default: true },
    isVerified: { type: Boolean, default: false },
    organizationId: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization' },
    onboardingCompleted: { type: Boolean, default: false },
    resetOtp: { type: String, select: false },
    resetOtpExpiry: { type: Date, select: false },
    resetToken: { type: String, select: false },
    resetTokenExpiry: { type: Date, select: false },
    verificationOtp: { type: String, select: false },
    verificationOtpExpiry: { type: Date, select: false },
    settings: {
      notifications: {
        highFitAlerts: { type: Boolean, default: true },
        deadlineReminders: { type: Boolean, default: true },
        weeklySummary: { type: Boolean, default: true },
        alertUpdates: { type: Boolean, default: true },
        systemAlerts: { type: Boolean, default: false },
      },
      preferences: {
        language: { type: String, default: 'en' },
        country: { type: String, default: 'US' },
        timezone: { type: String, default: 'America/New_York' },
      },
      reportEmail: { type: String },
      apiKey: { type: String },
    },
  },
  { timestamps: true }
);

userSchema.pre('save', async function () {
  if (!this.isModified('password')) return;
  this.password = await bcrypt.hash(this.password, 12);
});

userSchema.methods.comparePassword = async function (candidatePassword) {
  return bcrypt.compare(candidatePassword, this.password);
};

userSchema.plugin(mongoosePaginateV2);

userSchema.index({ organizationId: 1 });

module.exports = mongoose.model('User', userSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const digestSchema = new mongoose.Schema(
  {
    organization: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization', required: true },
    user: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
    orgName: { type: String },
    periodStart: { type: Date, required: true },
    periodEnd: { type: Date, required: true },
    matches: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Match' }],
    opportunities: [
      {
        title: { type: String },
        fitScore: { type: Number },
        amount: { type: Number },
        deadline: { type: Date },
      },
    ],
    aiIntro: { type: String },
    htmlContent: { type: String },
    status: { type: String, enum: ['draft', 'sent'], default: 'draft' },
    sentAt: { type: Date },
    itemCount: { type: Number, default: 0 },
  },
  { timestamps: true }
);

digestSchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('Digest', digestSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const followUpSchema = new mongoose.Schema(
  {
    application: { type: mongoose.Schema.Types.ObjectId, ref: 'Application', required: true },
    user: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
    organization: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization', required: true },
    funder: { type: mongoose.Schema.Types.ObjectId, ref: 'Funder' },
    opportunity: { type: mongoose.Schema.Types.ObjectId, ref: 'Opportunity' },

    followUpNumber: { type: Number },
    scheduledFor: { type: Date, required: true },
    emailSubject: { type: String },
    emailBody: { type: String },
    status: { type: String, enum: ['pending', 'sent', 'skipped'], default: 'pending' },
    sentAt: { type: Date },
  },
  { timestamps: true }
);

followUpSchema.plugin(mongoosePaginateV2);

followUpSchema.index({ application: 1 });
followUpSchema.index({ scheduledFor: 1, status: 1 });

module.exports = mongoose.model('FollowUp', followUpSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const funderSchema = new mongoose.Schema(
  {
    name: { type: String, required: true, trim: true },
    website: { type: String },
    contactName: { type: String },
    contactEmail: { type: String },
    contactPhone: { type: String },

    missionStatement: { type: String },
    locationFocus: [{ type: String }],
    fundingCategories: [{ type: String }],
    agencyTypesFunded: [{ type: String }],
    /** Equipment / program tags for matching (e.g. radios, repeaters, dispatch). */
    equipmentTags: [{ type: String }],
    /** When true, grant typically requires a local funding match. */
    localMatchRequired: { type: Boolean, default: false },

    avgGrantMin: { type: Number },
    avgGrantMax: { type: Number },
    deadline: { type: Date },
    cyclesPerYear: { type: Number },

    pastGrantsAwarded: [{ type: String }],
    notes: { type: String },

    maxApplicationsAllowed: { type: Number, default: 5 },
    currentApplicationCount: { type: Number, default: 0 },
    isLocked: { type: Boolean, default: false },

    status: { type: String, enum: ['active', 'inactive'], default: 'active' },
    addedBy: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  },
  { timestamps: true }
);

funderSchema.plugin(mongoosePaginateV2);

funderSchema.index({ status: 1, isLocked: 1 });

module.exports = mongoose.model('Funder', funderSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const matchSchema = new mongoose.Schema(
  {
    organization: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization', required: true },
    opportunity: { type: mongoose.Schema.Types.ObjectId, ref: 'Opportunity', required: true },
    fitScore: { type: Number, min: 0, max: 100, default: 0 },
    reasons: [{ type: String }],
    fitReasons: [{ type: String }],
    disqualifiers: [{ type: String }],
    recommendedAction: { type: String },
    state: { type: String },
    breakdown: {
      agencyType: { type: Number, default: 0 },
      geography: { type: Number, default: 0 },
      programKeyword: { type: Number, default: 0 },
      deadlineViability: { type: Number, default: 0 },
      awardSizeFit: { type: Number, default: 0 },
      timelineAlignment: { type: Number, default: 0 },
      dataCompleteness: { type: Number, default: 0 },
    },
    status: { type: String, enum: ['pending', 'approved', 'rejected'], default: 'pending' },
    scoreVersion: { type: String, default: 'v2' },
    lastUpdated: { type: Date, default: Date.now },
  },
  { timestamps: true }
);

matchSchema.index({ organization: 1, opportunity: 1 }, { unique: true });
matchSchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('Match', matchSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const opportunitySchema = new mongoose.Schema(
  {
    title: { type: String, required: true, trim: true },
    funder: { type: String, required: true, trim: true },
    deadline: { type: Date },
    minAmount: { type: Number },
    maxAmount: { type: Number },
    sourceUrl: { type: String },
    keywords: [{ type: String }],
    agencyTypes: [{ type: String }],
    description: { type: String },
    category: { type: String },
    equipmentTags: [{ type: String }],
    localMatchRequired: { type: Boolean, default: false },
    status: { type: String, enum: ['open', 'closing', 'closed'], default: 'open' },
    /** 0 = unlimited applications for this opportunity */
    maxApplicationsAllowed: { type: Number, default: 0 },
    currentApplicationCount: { type: Number, default: 0 },
    isLocked: { type: Boolean, default: false },
    createdBy: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  },
  { timestamps: true }
);

opportunitySchema.plugin(mongoosePaginateV2);

opportunitySchema.index({ status: 1, deadline: 1 });

module.exports = mongoose.model('Opportunity', opportunitySchema);

/**
 * Organization = Agency profile.
 *
 * Despite the collection name "organizations", every document here represents a
 * PUBLIC SAFETY AGENCY (fire dept, law enforcement, EMS, 911 center, etc.) that
 * has signed up for Red Dog Radios. The model is called "Organization" for
 * historical reasons. There is a separate thin `Agency` schema that is NOT used
 * in production — ignore it. All agency-related data lives here.
 *
 * One document per user account (createdBy → User._id).
 */
const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const organizationSchema = new mongoose.Schema(
  {
    name: { type: String, required: true, trim: true },
    email: { type: String, lowercase: true, trim: true },
    location: { type: String },
    websiteUrl: { type: String },
    missionStatement: { type: String },
    focusAreas: [{ type: String }],
    agencyTypes: [
      {
        type: String,
        trim: true,
      },
    ],
    programAreas: [{ type: String }],
    budgetRange: {
      type: String,
      enum: ['under_25k', '25k_150k', '150k_500k', '500k_plus'],
    },
    timeline: { type: String, enum: ['urgent', 'planned'] },
    goals: [{ type: String }],
    // Extended agency profile fields
    populationServed: { type: Number },
    coverageArea: { type: String },
    numberOfStaff: { type: Number },
    currentEquipment: { type: String },
    mainProblems: [{ type: String }],
    fundingPriorities: [{ type: String }],
    /** Whether the agency can meet a local match requirement when applying. */
    canMeetLocalMatch: { type: Boolean },

    matchCount: { type: Number, default: 0 },
    status: { type: String, enum: ['active', 'inactive'], default: 'active' },
    createdBy: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
    lastMatchRecomputedAt: { type: Date },
  },
  { timestamps: true }
);

organizationSchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('Organization', organizationSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const outboxSchema = new mongoose.Schema(
  {
    recipient: { type: String, required: true },
    recipientName: { type: String },
    subject: { type: String, required: true },
    htmlBody: { type: String, required: true },
    emailType: {
      type: String,
      enum: ['weekly_digest', 'alert_digest', 'outreach', 'manual', 'followup_reminder'],
      default: 'manual',
    },
    /** When set, processQueue will not send until this datetime (UTC). */
    scheduledFor: { type: Date },
    status: { type: String, enum: ['pending', 'sent', 'failed'], default: 'pending' },
    retryCount: { type: Number, default: 0 },
    providerMessageId: { type: String },
    errorMessage: { type: String },
    sentAt: { type: Date },
    isTest: { type: Boolean, default: false },
    emailKey: { type: String },
    relatedOrganization: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization' },
    relatedUser: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  },
  { timestamps: true }
);

outboxSchema.index({ emailKey: 1 }, { unique: true, sparse: true });
outboxSchema.index({ status: 1, scheduledFor: 1 });
outboxSchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('Outbox', outboxSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const outreachSchema = new mongoose.Schema(
  {
    organization: { type: mongoose.Schema.Types.ObjectId, ref: 'Organization', required: true },
    funder: { type: mongoose.Schema.Types.ObjectId, ref: 'Funder' },
    opportunity: { type: mongoose.Schema.Types.ObjectId, ref: 'Opportunity' },
    user: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },

    subject: { type: String, required: true },
    contactName: { type: String },
    body: { type: String, required: true },

    status: { type: String, enum: ['draft', 'sent'], default: 'draft' },
    sentAt: { type: Date },
  },
  { timestamps: true }
);

outreachSchema.plugin(mongoosePaginateV2);

module.exports = mongoose.model('Outreach', outreachSchema);

const mongoose = require('mongoose');
const mongoosePaginateV2 = require('mongoose-paginate-v2');

const winSchema = new mongoose.Schema(
  {
    applicationId: { type: mongoose.Schema.Types.ObjectId, ref: 'Application' },
    agencyType: { type: String, required: true },
    fundingType: { type: String },
    projectType: { type: String },
    funderName: { type: String },
    awardAmount: { type: Number },

    problemStatement: { type: String },
    communityImpact: { type: String },
    proposedSolution: { type: String },
    measurableOutcomes: { type: String },
    urgency: { type: String },
    budgetSummary: { type: String },

    winFactors: [{ type: String }],
    lessonsLearned: { type: String },
  },
  { timestamps: true }
);

winSchema.plugin(mongoosePaginateV2);

winSchema.index({ agencyType: 1, funderName: 1 });

module.exports = mongoose.model('Win', winSchema);
